import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate, Link } from 'react-router-dom';
import { ArrowLeft, Save, MapPin, User, Lock } from 'lucide-react';

const VendorRegister = () => {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [formData, setFormData] = useState({
    username: '',
    password: '',
    name: '',
    phone: '',
    aadhaar: '',
    category: 'VEGETABLE',
    latitude: '',
    longitude: '',
    address: ''
  });

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const getCurrentLocation = () => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition((position) => {
        setFormData({
          ...formData,
          latitude: position.coords.latitude,
          longitude: position.coords.longitude
        });
      }, (err) => {
        alert("Unable to retrieve location: " + err.message);
      });
    } else {
      alert("Geolocation is not supported by your browser");
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await axios.post('http://localhost:8080/api/vendors/register', {
        ...formData,
        latitude: parseFloat(formData.latitude),
        longitude: parseFloat(formData.longitude)
      });
      alert('Registration successful! You can now login after admin approval. Your unique QR code will be generated upon approval.');
      navigate('/login');
    } catch (err) {
      alert('Registration failed: ' + (err.response?.data?.message || err.message));
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gray-100 py-12 px-4 sm:px-6 lg:px-8">
      <div className="max-w-2xl mx-auto space-y-6">
        <div className="flex items-center gap-4">
          <Link to="/login" className="p-2 hover:bg-gray-200 rounded-full transition">
            <ArrowLeft size={20} />
          </Link>
          <div>
            <h1 className="text-2xl font-bold text-gray-800">Vendor Self-Registration</h1>
            <p className="text-gray-500 text-sm">Join the Smart Street Vendor Management System</p>
          </div>
        </div>

        <form onSubmit={handleSubmit} className="bg-white rounded-xl shadow-md p-8 space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="md:col-span-2">
              <h3 className="font-bold text-gray-700 flex items-center gap-2 border-b pb-2 mb-4">
                <User size={18} className="text-smc-blue" /> Account Credentials
              </h3>
            </div>
            <div className="space-y-1">
              <label className="text-sm font-semibold text-gray-600">Username</label>
              <div className="relative">
                <input name="username" required value={formData.username} onChange={handleChange} className="w-full pl-10 pr-4 py-2 border rounded-lg outline-none focus:ring-2 focus:ring-smc-blue" placeholder="Pick a username" />
                <User size={16} className="absolute left-3 top-3 text-gray-400" />
              </div>
            </div>
            <div className="space-y-1">
              <label className="text-sm font-semibold text-gray-600">Password</label>
              <div className="relative">
                <input name="password" type="password" required value={formData.password} onChange={handleChange} className="w-full pl-10 pr-4 py-2 border rounded-lg outline-none focus:ring-2 focus:ring-smc-blue" placeholder="Create a password" />
                <Lock size={16} className="absolute left-3 top-3 text-gray-400" />
              </div>
            </div>

            <div className="md:col-span-2">
              <h3 className="font-bold text-gray-700 flex items-center gap-2 border-b pb-2 mb-4 mt-4">
                <Save size={18} className="text-smc-blue" /> Personal Information
              </h3>
            </div>
            <div className="space-y-1">
              <label className="text-sm font-semibold text-gray-600">Full Name</label>
              <input name="name" required value={formData.name} onChange={handleChange} className="w-full px-4 py-2 border rounded-lg outline-none focus:ring-2 focus:ring-smc-blue" placeholder="Your full name" />
            </div>
            <div className="space-y-1">
              <label className="text-sm font-semibold text-gray-600">Phone Number</label>
              <input name="phone" required value={formData.phone} onChange={handleChange} className="w-full px-4 py-2 border rounded-lg outline-none focus:ring-2 focus:ring-smc-blue" placeholder="10-digit mobile number" />
            </div>
            <div className="space-y-1">
              <label className="text-sm font-semibold text-gray-600">Aadhaar Number</label>
              <input name="aadhaar" required value={formData.aadhaar} onChange={handleChange} className="w-full px-4 py-2 border rounded-lg outline-none focus:ring-2 focus:ring-smc-blue" placeholder="XXXX-XXXX-XXXX" />
            </div>
            <div className="space-y-1">
              <label className="text-sm font-semibold text-gray-600">Vending Category</label>
              <select name="category" value={formData.category} onChange={handleChange} className="w-full px-4 py-2 border rounded-lg outline-none focus:ring-2 focus:ring-smc-blue">
                <option value="VEGETABLE">Vegetables</option>
                <option value="FRUIT">Fruits</option>
                <option value="FOOD">Fast Food / Snacks</option>
                <option value="TEA">Tea / Coffee</option>
                <option value="PAN_SHOP">Pan Shop</option>
                <option value="OTHER">Other</option>
              </select>
            </div>
          </div>

          <div className="pt-4">
            <div className="flex justify-between items-center mb-4">
              <h3 className="font-bold text-gray-700 flex items-center gap-2">
                <MapPin size={18} className="text-smc-blue" /> Vending Location
              </h3>
              <button type="button" onClick={getCurrentLocation} className="bg-blue-50 text-smc-blue px-3 py-1 rounded-full text-sm font-semibold hover:bg-blue-100 transition">
                Auto-detect GPS
              </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6 bg-blue-50/50 p-6 rounded-xl border border-blue-100">
              <div className="space-y-1">
                <label className="text-sm font-semibold text-gray-600">Latitude</label>
                <input name="latitude" required type="number" step="any" value={formData.latitude} onChange={handleChange} className="w-full px-4 py-2 border rounded-lg outline-none focus:ring-2 focus:ring-smc-blue bg-white" placeholder="0.000000" />
              </div>
              <div className="space-y-1">
                <label className="text-sm font-semibold text-gray-600">Longitude</label>
                <input name="longitude" required type="number" step="any" value={formData.longitude} onChange={handleChange} className="w-full px-4 py-2 border rounded-lg outline-none focus:ring-2 focus:ring-smc-blue bg-white" placeholder="0.000000" />
              </div>
              <div className="md:col-span-2 space-y-1">
                <label className="text-sm font-semibold text-gray-600">Specific Address / Landmark</label>
                <input name="address" value={formData.address} onChange={handleChange} className="w-full px-4 py-2 border rounded-lg outline-none focus:ring-2 focus:ring-smc-blue bg-white" placeholder="e.g. Near Solapur Central Bus Stand" />
              </div>
            </div>
          </div>

          <div className="pt-4">
            <button 
              type="submit" 
              disabled={loading}
              className="w-full bg-smc-blue text-white py-4 rounded-xl font-bold hover:bg-blue-800 transition shadow-lg flex items-center justify-center gap-2 disabled:opacity-50"
            >
              {loading ? 'Processing...' : 'SUBMIT REGISTRATION APPLICATION'}
            </button>
            <p className="text-center text-xs text-gray-500 mt-4 px-8">
              By registering, you agree to comply with SMC street vending bylaws. Your application will be reviewed by city officials.
            </p>
          </div>
        </form>
      </div>
    </div>
  );
};

export default VendorRegister;
